namespace sv_533e30ed29f649dfbabf082c0f95def8.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@rendermode InteractiveServer
@using sv_533e30ed29f649dfbabf082c0f95def8.Services
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

<div class="catalog-layout">
    @* ───── Left sidebar: filters ───── *@
    <aside class="catalog-sidebar">
        <h4>Filters</h4>

        @* Category checkboxes *@
        <div class="filter-section">
            <h6>Category</h6>
            @if (_categories is not null)
            {
                @foreach (var category in _categories)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                               checked="@_selectedCategories.Contains(category)"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                    </div>
                }
            }
        </div>

        @* Price range *@
        <div class="filter-section">
            <h6>Price Range</h6>
            <div class="mb-2">
                <label class="form-label form-label-sm">Min Price</label>
                <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                       @bind="_minPrice" placeholder="0.00" />
            </div>
            <div class="mb-2">
                <label class="form-label form-label-sm">Max Price</label>
                <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                       @bind="_maxPrice" placeholder="No limit" />
            </div>
        </div>

        @* In-stock toggle *@
        <div class="filter-section">
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="inStockOnly"
                       @bind="_inStockOnly" />
                <label class="form-check-label" for="inStockOnly">In Stock Only</label>
            </div>
        </div>

        @* Action buttons *@
        <div class="filter-actions">
            <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    @* ───── Main content area ───── *@
    <section class="catalog-main">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
                <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
                <span class="ms-3">Loading products…</span>
            </div>
        }
        else if (_result is not null)
        {
            @* Toolbar *@
            <div class="catalog-toolbar">
                <div class="d-flex align-items-center gap-3">
                    <label class="form-label mb-0 text-nowrap" for="sortSelect">Sort by</label>
                    <select id="sortSelect" class="form-select form-select-sm w-auto"
                            @bind="_sortBy" @bind:after="LoadProducts">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>

                <span class="text-muted showing-label">
                    @{
                        int first = (_result.Page - 1) * _result.PageSize + 1;
                        int last = Math.Min(_result.Page * _result.PageSize, _result.TotalCount);
                    }
                    Showing @first–@last of @_result.TotalCount products
                </span>
            </div>

            @* Product grid *@
            @if (_result.Items.Count == 0)
            {
                <div class="text-center py-5 text-muted">
                    <h5>No products found</h5>
                    <p>Try adjusting your filters to see more results.</p>
                </div>
            }
            else
            {
                <div class="product-grid">
                    @foreach (var product in _result.Items)
                    {
                        <div class="card product-card" @onclick="() => OnProductSelected(product)">
                            <div class="product-image-placeholder" title="@product.Name">
                                <span>@product.Name</span>
                            </div>
                            <div class="card-body">
                                <h6 class="card-title text-truncate" title="@product.Name">@product.Name</h6>
                                <p class="card-text fw-bold mb-1">@product.Price.ToString("C")</p>
                                <div class="mb-1" title="@($"Rating: {product.Rating:F1}/5")">
                                    @RenderStars(product.Rating)
                                </div>
                                @if (!product.InStock)
                                {
                                    <span class="badge bg-danger mb-2">Out of Stock</span>
                                }
                                <button class="btn btn-sm btn-success w-100"
                                        disabled="@(!product.InStock)"
                                        @onclick="() => AddToCart(product)"
                                        @onclick:stopPropagation="true">
                                    Add to Cart
                                </button>
                            </div>
                        </div>
                    }
                </div>
            }

            @* Pagination *@
            @if (_totalPages > 1)
            {
                <nav aria-label="Product pagination" class="mt-4">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(_currentPage <= 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage - 1)"
                                    disabled="@(_currentPage <= 1)">Previous</button>
                        </li>

                        @foreach (var p in GetPageNumbers())
                        {
                            <li class="page-item @(p == _currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                            </li>
                        }

                        <li class="page-item @(_currentPage >= _totalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage + 1)"
                                    disabled="@(_currentPage >= _totalPages)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </section>
</div>

@code {
    /// <summary>Raised when a product card is clicked so the parent can navigate to a detail page.</summary>
    [Parameter] public EventCallback<Product> OnProductClicked { get; set; }

    private const int PageSize = 12;

    // Filter state
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    // Results state
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalPages;
    private PagedResult<Product>? _result;

    // UI state
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialData();
    }

    private async Task LoadInitialData()
    {
        _loading = true;
        _error = null;

        try
        {
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProductsCore();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            await LoadProductsCore();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProductsCore()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );

        _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        _totalPages = (_result.TotalCount + PageSize - 1) / PageSize;
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > _totalPages) return;
        _currentPage = page;
        await LoadProducts();
    }

    private async Task RetryLoad() => await LoadInitialData();

    private async Task OnProductSelected(Product product)
    {
        if (OnProductClicked.HasDelegate)
            await OnProductClicked.InvokeAsync(product);
    }

    private void AddToCart(Product product)
    {
        // Placeholder – wire up to a cart service when available
    }

    private static MarkupString RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        int empty = 5 - full;
        return new MarkupString(
            $"<span class=\"text-warning\">{new string('★', full)}</span>" +
            $"<span class=\"text-muted\">{new string('☆', empty)}</span>"
        );
    }

    /// <summary>Returns a window of page numbers around the current page.</summary>
    private IEnumerable<int> GetPageNumbers()
    {
        const int window = 2;
        int start = Math.Max(1, _currentPage - window);
        int end = Math.Min(_totalPages, _currentPage + window);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}

/* ───── Layout ───── */
.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
    border-right: 1px solid #dee2e6;
    padding-right: 1.25rem;
}

.catalog-main {
    flex: 1 1 75%;
    min-width: 0;
}

/* ───── Filter sections ───── */
.filter-section {
    margin-bottom: 1.25rem;
}

.filter-actions {
    margin-top: 1.5rem;
}

/* ───── Toolbar ───── */
.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 0.75rem;
    margin-bottom: 1.25rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid #dee2e6;
}

.showing-label {
    font-size: 0.875rem;
}

/* ───── Product grid ───── */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.15s ease-in-out, transform 0.15s ease-in-out;
}

.product-card:hover {
    box-shadow: 0 .5rem 1rem rgba(0, 0, 0, .12);
    transform: translateY(-2px);
}

.product-image-placeholder {
    height: 160px;
    background-color: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.875rem;
    text-align: center;
    padding: 1rem;
    border-bottom: 1px solid #dee2e6;
}

/* ───── Responsive ───── */
@media (max-width: 768px) {
    .catalog-layout {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
        max-width: 100%;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
        padding-right: 0;
        padding-bottom: 1rem;
        margin-bottom: 1rem;
    }
}

