@code {
    /// <summary>Raised when a product card is clicked so the parent can navigate to a detail page.</summary>
    [Parameter] public EventCallback<Product> OnProductClicked { get; set; }

    private const int PageSize = 12;

    // Filter state
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    // Results state
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalPages;
    private PagedResult<Product>? _result;

    // UI state
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialData();
    }

    private async Task LoadInitialData()
    {
        _loading = true;
        _error = null;

        try
        {
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProductsCore();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            await LoadProductsCore();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProductsCore()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );

        _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        _totalPages = (_result.TotalCount + PageSize - 1) / PageSize;
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > _totalPages) return;
        _currentPage = page;
        await LoadProducts();
    }

    private async Task RetryLoad() => await LoadInitialData();

    private async Task OnProductSelected(Product product)
    {
        if (OnProductClicked.HasDelegate)
            await OnProductClicked.InvokeAsync(product);
    }

    private void AddToCart(Product product)
    {
        // Placeholder – wire up to a cart service when available
    }

    private static MarkupString RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        int empty = 5 - full;
        return new MarkupString(
            $"<span class=\"text-warning\">{new string('★', full)}</span>" +
            $"<span class=\"text-muted\">{new string('☆', empty)}</span>"
        );
    }

    /// <summary>Returns a window of page numbers around the current page.</summary>
    private IEnumerable<int> GetPageNumbers()
    {
        const int window = 2;
        int start = Math.Max(1, _currentPage - window);
        int end = Math.Min(_totalPages, _currentPage + window);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}

