+        _maxPrice = null;
+        _inStockOnly = false;
+        _currentPage = 1;
+        await LoadProducts();
+    }
+
+    private async Task GoToPage(int page)
+    {
+        if (page < 1 || page > _totalPages) return;
+        _currentPage = page;
+        await LoadProducts();
+    }
+
+    private async Task RetryLoad() => await LoadInitialData();
+
+    private async Task OnProductSelected(Product product)
+    {
+        if (OnProductClicked.HasDelegate)
+            await OnProductClicked.InvokeAsync(product);
+    }
+
+    private void AddToCart(Product product)
+    {
+        // Placeholder – wire up to a cart service when available
+    }
+
+    private static MarkupString RenderStars(double rating)
+    {
+        int full = (int)Math.Round(rating);
+        int empty = 5 - full;
+        return new MarkupString(
+            $"<span class=\"text-warning\">{new string('★', full)}</span>" +
+            $"<span class=\"text-muted\">{new string('☆', empty)}</span>"
+        );
+    }
+
+    /// <summary>Returns a window of page numbers around the current page.</summary>
+    private IEnumerable<int> GetPageNumbers()
+    {
+        const int window = 2;
+        int start = Math.Max(1, _currentPage - window);
+        int end = Math.Min(_totalPages, _currentPage + window);
+
+        for (int i = start; i <= end; i++)
+            yield return i;
+    }
+}
