/* ───── Layout ───── */
.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
    border-right: 1px solid #dee2e6;
    padding-right: 1.25rem;
}

.catalog-main {
    flex: 1 1 75%;
    min-width: 0;
}

/* ───── Filter sections ───── */
.filter-section {
    margin-bottom: 1.25rem;
}

.filter-actions {
    margin-top: 1.5rem;
}

/* ───── Toolbar ───── */
.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 0.75rem;
    margin-bottom: 1.25rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid #dee2e6;
}

.showing-label {
    font-size: 0.875rem;
}

/* ───── Product grid ───── */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.15s ease-in-out, transform 0.15s ease-in-out;
}

.product-card:hover {
    box-shadow: 0 .5rem 1rem rgba(0, 0, 0, .12);
    transform: translateY(-2px);
}

.product-image-placeholder {
    height: 160px;
    background-color: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.875rem;
    text-align: center;
    padding: 1rem;
    border-bottom: 1px solid #dee2e6;
}

/* ───── Responsive ───── */
@media (max-width: 768px) {
    .catalog-layout {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
        max-width: 100%;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
        padding-right: 0;
        padding-bottom: 1rem;
        margin-bottom: 1rem;
    }
}

